import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import './Auth.css';

export default function Register() {
  const [form, setForm] = useState({
    name: '',
    email: '',
    password: '',
    confirm: '',
    usn: '',
    roomNumber: '',
    phoneNumber: ''
  });
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(false);
  const [fieldErrors, setFieldErrors] = useState({});
  const navigate = useNavigate();

  const handleChange = e => {
    setForm({ ...form, [e.target.name]: e.target.value });
    // Clear field-specific error when user types
    if (fieldErrors[e.target.name]) {
      setFieldErrors({ ...fieldErrors, [e.target.name]: '' });
    }
  };

  const validateForm = () => {
    const errors = {};
    if (!form.name.trim()) errors.name = 'Name is required';
    if (!form.email.trim()) errors.email = 'Email is required';
    else if (!/\S+@\S+\.\S+/.test(form.email)) errors.email = 'Email is invalid';
    if (!form.usn.trim()) errors.usn = 'USN is required';
    if (!form.roomNumber.trim()) errors.roomNumber = 'Room number is required';
    if (!form.phoneNumber.trim()) errors.phoneNumber = 'Phone number is required';
    if (!form.password) errors.password = 'Password is required';
    else if (form.password.length < 3) errors.password = 'Password must be at least 3 characters';
    if (form.password !== form.confirm) errors.confirm = 'Passwords do not match';
    
    setFieldErrors(errors);
    return Object.keys(errors).length === 0;
  };

  const handleSubmit = async e => {
    e.preventDefault();
    setError('');
    setSuccess('');
    
    if (!validateForm()) {
      return;
    }
    
    setLoading(true);
    
    try {
      console.log('Sending registration data:', {
        name: form.name,
        email: form.email,
        password: form.password,
        usn: form.usn,
        roomNumber: form.roomNumber,
        phoneNumber: form.phoneNumber
      });
      
      const response = await axios.post('http://localhost:5000/api/auth/register', {
        name: form.name,
        email: form.email,
        password: form.password,
        usn: form.usn,
        roomNumber: form.roomNumber,
        phoneNumber: form.phoneNumber
      });
      
      console.log('Registration response:', response.data);
      setSuccess('Registration successful! Redirecting to login...');
      
      // Clear form
      setForm({
        name: '',
        email: '',
        password: '',
        confirm: '',
        usn: '',
        roomNumber: '',
        phoneNumber: ''
      });
      
      setTimeout(() => navigate('/login'), 2000);
    } catch (err) {
      console.error('Registration error:', err.response || err);
      
      if (err.code === 'ERR_NETWORK') {
        setError('Cannot connect to server. Make sure backend is running on port 5000');
      } else if (err.response?.status === 400) {
        setError(err.response.data?.message || 'Registration failed: Invalid data');
      } else if (err.response?.status === 500) {
        setError('Server error. Please try again later.');
      } else {
        setError(err.response?.data?.message || 'Registration failed');
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-wrapper">
      <div className="auth-card">
        <div className="auth-header">
          <h1>Hostel<span>Hub</span></h1>
          <p>Student Registration</p>
        </div>
        <div className="auth-form">
          {error && <div className="error-message">{error}</div>}
          {success && <div className="success-message">{success}</div>}
          
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label>Full Name *</label>
              <input 
                name="name" 
                value={form.name} 
                onChange={handleChange} 
                placeholder="Enter your full name"
                className={fieldErrors.name ? 'error-input' : ''}
                required 
              />
              {fieldErrors.name && <small className="field-error">{fieldErrors.name}</small>}
            </div>
            
            <div className="form-group">
              <label>Email *</label>
              <input 
                type="email" 
                name="email" 
                value={form.email} 
                onChange={handleChange} 
                placeholder="your@email.com"
                className={fieldErrors.email ? 'error-input' : ''}
                required 
              />
              {fieldErrors.email && <small className="field-error">{fieldErrors.email}</small>}
            </div>
            
            <div className="form-group">
              <label>USN *</label>
              <input 
                name="usn" 
                value={form.usn} 
                onChange={handleChange} 
                placeholder="e.g., 1MS20CS001"
                className={fieldErrors.usn ? 'error-input' : ''}
                required 
              />
              {fieldErrors.usn && <small className="field-error">{fieldErrors.usn}</small>}
            </div>
            
            <div className="form-group">
              <label>Room Number *</label>
              <input 
                name="roomNumber" 
                value={form.roomNumber} 
                onChange={handleChange} 
                placeholder="e.g., 101"
                className={fieldErrors.roomNumber ? 'error-input' : ''}
                required 
              />
              {fieldErrors.roomNumber && <small className="field-error">{fieldErrors.roomNumber}</small>}
            </div>
            
            <div className="form-group">
              <label>Phone Number *</label>
              <input 
                name="phoneNumber" 
                value={form.phoneNumber} 
                onChange={handleChange} 
                placeholder="10-digit mobile number"
                className={fieldErrors.phoneNumber ? 'error-input' : ''}
                required 
              />
              {fieldErrors.phoneNumber && <small className="field-error">{fieldErrors.phoneNumber}</small>}
            </div>
            
            <div className="form-group">
              <label>Password *</label>
              <input 
                type="password" 
                name="password" 
                value={form.password} 
                onChange={handleChange} 
                placeholder="Minimum 3 characters"
                className={fieldErrors.password ? 'error-input' : ''}
                required 
              />
              {fieldErrors.password && <small className="field-error">{fieldErrors.password}</small>}
            </div>
            
            <div className="form-group">
              <label>Confirm Password *</label>
              <input 
                type="password" 
                name="confirm" 
                value={form.confirm} 
                onChange={handleChange} 
                placeholder="Re-enter password"
                className={fieldErrors.confirm ? 'error-input' : ''}
                required 
              />
              {fieldErrors.confirm && <small className="field-error">{fieldErrors.confirm}</small>}
            </div>
            
            <button type="submit" className="btn-login" disabled={loading}>
              {loading ? 'Registering...' : 'Register'}
            </button>
            
            <div className="info-box">
              Already have an account? <a href="/login">Login here</a>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}
